  PRIMARY KEY (`rating_id`) /*T![clustered_index] CLUSTERED */,
  UNIQUE KEY `rating_uuid` (`rating_uuid`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin;

